class Solution {
public:
    int maxScore(vector<int>& nums) {
        int n = nums.size();
        int max_score = 0;
        for (int i = 0; i < n; i++) {
            int gcd_sum = 0;
            for (int j = 0; j < n; j++) {
                gcd_sum += gcd(nums[i], nums[j]);
            }
            max_score = max(max_score, gcd_sum);
        }
        return max_score;
    }

    int gcd(int a, int b) {
        while (b != 0) {
            int temp = b;
            b = a % b;
            a = temp;
        }
        return a;
    }
};
